            <div style={{width:'24px',height:'24px',background:'#ec4899',color:'#fff',borderRadius:'12px',display:'flex',alignItems:'center',justifyContent:'center',fontWeight:'bold',fontSize:'11px',flexShrink:0}}>S</div>
